from dataclasses import dataclass
from typing import Any
import numpy as np

@dataclass
class Decision:
    action: str
    confidence: float   # 0.0 – 1.0
    explanation: str
    metadata: dict

class ConfidenceGatedHITL:
    def __init__(
        self,
        auto_threshold: float = 0.90,   # above this → automate
        reject_threshold: float = 0.40, # below this → reject without escalating
        escalation_queue=None,
    ):
        self.auto_threshold = auto_threshold
        self.reject_threshold = reject_threshold
        self.queue = escalation_queue

    def process(self, decision: Decision) -> str:
        if decision.confidence >= self.auto_threshold:
            return self._execute(decision)
        elif decision.confidence < self.reject_threshold:
            return self._auto_reject(decision)
        else:
            return self._escalate(decision)

    def _execute(self, d: Decision) -> str:
        # Execute action autonomously
        return f'AUTO: {d.action} (conf={d.confidence:.2f})'

    def _auto_reject(self, d: Decision) -> str:
        return f'REJECTED: confidence {d.confidence:.2f} below floor'

    def _escalate(self, d: Decision) -> str:
        if self.queue:
            self.queue.put(d)
        return f'ESCALATED: awaiting human review (conf={d.confidence:.2f})'

# Example
hitl = ConfidenceGatedHITL(auto_threshold=0.90, reject_threshold=0.40)
cases = [
    Decision('approve_loan', 0.95, 'Strong credit history', {}),
    Decision('approve_loan', 0.65, 'Mixed signals', {}),
    Decision('approve_loan', 0.25, 'Insufficient data', {}),
]
for c in cases:
    print(hitl.process(c))

import heapq
from datetime import datetime, timedelta
from dataclasses import dataclass, field

@dataclass(order=True)
class ReviewItem:
    priority: float          # lower = higher priority
    deadline: datetime = field(compare=False)
    decision: object = field(compare=False)

class ReviewQueue:
    def __init__(self, default_sla_minutes: int = 60):
        self._heap = []
        self.sla = timedelta(minutes=default_sla_minutes)

    def put(self, decision, urgency: float = 0.5):
        deadline = datetime.utcnow() + self.sla
        # Priority: blend urgency and deadline proximity
        priority = -urgency  # higher urgency = lower heap value
        item = ReviewItem(priority=priority, deadline=deadline, decision=decision)
        heapq.heappush(self._heap, item)

    def get_next(self) -> ReviewItem | None:
        if not self._heap:
            return None
        item = heapq.heappop(self._heap)
        if datetime.utcnow() > item.deadline:
            # SLA breached — auto-escalate to senior reviewer or auto-reject
            return self._handle_sla_breach(item)
        return item

    def _handle_sla_breach(self, item: ReviewItem) -> ReviewItem:
        print(f'SLA BREACH: {item.decision.action} — escalating to senior')
        return item  # in practice: route to senior queue

    def depth(self) -> int:
        return len(self._heap)

import numpy as np

def calibration_bins(
    y_true: np.ndarray,
    y_prob: np.ndarray,
    n_bins: int = 10,
) -> list[dict]:
    """Compute per-bin error rate vs confidence for threshold calibration."""
    bins = np.linspace(0, 1, n_bins + 1)
    results = []
    for lo, hi in zip(bins[:-1], bins[1:]):
        mask = (y_prob >= lo) & (y_prob < hi)
        if mask.sum() == 0:
            continue
        y_pred = (y_prob[mask] > 0.5).astype(int)
        error_rate = (y_pred != y_true[mask]).mean()
        results.append({
            'bin': f'{lo:.1f}-{hi:.1f}',
            'n': int(mask.sum()),
            'error_rate': round(float(error_rate), 4),
            'mean_conf': round(float(y_prob[mask].mean()), 4),
        })
    return results

def find_threshold(calibration: list[dict], cost_ratio: float) -> float:
    """cost_ratio = C_human / C_auto. Find lowest conf bin where error <= ratio."""
    for row in sorted(calibration, key=lambda r: -r['mean_conf']):
        if row['error_rate'] <= cost_ratio:
            return row['mean_conf']
    return 1.0  # all cases need human review

from enum import Enum
from dataclasses import dataclass
from typing import Callable

class Reversibility(Enum):
    REVERSIBLE   = 'reversible'
    IRREVERSIBLE = 'irreversible'

@dataclass
class AgentStep:
    description: str
    tool: str
    args: dict
    reversibility: Reversibility
    undo_fn: Callable | None = None

class AgentPlanExecutor:
    def __init__(self, human_approver: Callable):
        self.approver = human_approver
        self.executed: list[AgentStep] = []

    def run_plan(self, steps: list[AgentStep]) -> list[str]:
        results = []
        for step in steps:
            if step.reversibility == Reversibility.IRREVERSIBLE:
                if not self.approver(step, self.executed):
                    self._rollback()
                    return results + ['ABORTED: human rejected irreversible step']
            result = step.tool(**step.args)  # type: ignore
            self.executed.append(step)
            results.append(result)
        return results

    def _rollback(self) -> None:
        for step in reversed(self.executed):
            if step.undo_fn:
                step.undo_fn()
        self.executed.clear()
